import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Divider } from '@mui/material';
import response from './response.json';

interface BookingDetails {
  hotelName: string;
  checkInDate: string;
  checkOutDate: string;
  roomType: string;
  guests: number;
}

interface PriceBreakdown {
  roomRate: number;
  nights: number;
  taxesAndFees: number;
  totalPrice: number;
}

interface WidgetData {
  bookingDetails: BookingDetails;
  priceBreakdown: PriceBreakdown;
}

export default function Widget() {
  const widgetData = response.data as WidgetData;
  const { bookingDetails, priceBreakdown } = widgetData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#F5F5F5', boxShadow: 'inset 1px 1px 5px rgba(0, 0, 0, 0.1), 1px 1px 5px rgba(0, 0, 0, 0.1)' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: response.meta.primaryColor }}>
              {bookingDetails.hotelName}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              {`${bookingDetails.roomType} • ${bookingDetails.guests} Guest(s)`}
            </Typography>
          </Box>

          <Divider light />

          <Typography variant="body2" color="text.secondary">
            Check-in: {bookingDetails.checkInDate}
          </Typography>
          <Typography variant="body2" color="text.secondary">
            Check-out: {bookingDetails.checkOutDate}
          </Typography>

          <Divider light />

          <Stack direction="row" spacing={2} justifyContent="space-between">
            <Box>
              <Typography variant="body2" color="text.secondary">
                Room Rate
              </Typography>
              <Typography variant="body2" sx={{ fontWeight: 500 }}>
                ${priceBreakdown.roomRate} x {priceBreakdown.nights} nights
              </Typography>
            </Box>
            <Box>
              <Typography variant="body2" color="text.secondary">
                Taxes & Fees
              </Typography>
              <Typography variant="body2" sx={{ fontWeight: 500 }}>
                ${priceBreakdown.taxesAndFees}
              </Typography>
            </Box>
          </Stack>

          <Divider light />

          <Box>
            <Typography variant="body2" color="text.secondary">
              Total Price
            </Typography>
            <Typography variant="h6" sx={{ fontWeight: 600, color: response.meta.accentColor }}>
              ${priceBreakdown.totalPrice}
            </Typography>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
